        return false;
    }
    return containsAny(cs, searchChars.toCharArray());
}

public static int indexOfAnyBut(CharSequence cs, char[] searchChars) {
    if (isEmpty(cs) || ArrayUtils.isEmpty(searchChars)) {
        return INDEX_NOT_FOUND;
    }
    int csLen = cs.length();
    int csLast = csLen - 1;
    int searchLen = searchChars.length;
    int searchLast = searchLen - 1;
    outer:
    for (int i = 0; i < csLen; i++) {
        char ch = cs.charAt(i);
        for (int j = 0; j < searchLen; j++) {
            if (searchChars[j] == ch) {
                if (i < csLast && j < searchLast && ch >= Character.MIN_HIGH_SURROGATE && ch <= Character.MAX_HIGH_SURROGATE) {
                    // ch is a high surrogate
                    if (searchChars[j + 1] == cs.charAt(i + 1)) {
                        i++;
                        continue outer;
                    }
                } else {
                    // ch is in the Basic Multilingual Plane
                    continue outer;
                }
            }
        }
        return i;
    }
    return INDEX_NOT_FOUND;
}

public static int indexOfAnyBut(String str, String searchChars) {
    if (isEmpty(str) || isEmpty(searchChars)) {
        return INDEX_NOT_FOUND;
    }
    int strLen = str.length();
    int strLast = strLen - 1;
    for (int i = 0; i < strLen; i++) {
        char ch = str.charAt(i);
        int searchIndex = searchChars.indexOf(ch);
        if (searchIndex < 0) {
            return i;
        }
        if (i < strLast && searchIndex < searchChars.length() - 1 && ch >= Character.MIN_HIGH_SURROGATE && ch <= Character.MAX_HIGH_SURROGATE) {
            // ch is a high surrogate
            if (searchChars.charAt(searchIndex + 1) == str.charAt(i + 1)) {
                i++;
            } else {
                return i;
            }
        }
    }
    return INDEX_NOT_FOUND;
}

